/bin/bash -lc "cat > healthstats/healthstats.module <<'EOF'
<?php

/**
 * @file
 * Provides a JSON endpoint with basic site health statistics.
 */

/**
 * Implements hook_permission().
 */
function healthstats_permission() {
  return array(
    'view healthstats' => array(
      'title' => t('View health stats'),
      'description' => t('View the site health statistics JSON endpoint.'),
    ),
  );
}

/**
 * Implements hook_menu().
 */
function healthstats_menu() {
  "'$items['"'api/healthstats'] = array(
    'title' => 'Health stats',
    'page callback' => 'healthstats_json',
    'access arguments' => array('view healthstats'),
    'delivery callback' => 'drupal_json_output',
    'type' => MENU_CALLBACK,
  );
  return "'$items;
}

/**
 * Page callback for api/healthstats.
 *
 * Returns a data array; JSON conversion is handled by the delivery callback.
 *
 * @return array
 *   Associative array with '"'users' and 'nodes' counts.
 */
function healthstats_json() {
  "'$users = db_query('"'SELECT COUNT(*) FROM {users} WHERE status = :status', array(':status' => 1))->fetchField();
  "'$nodes = db_query('"'SELECT COUNT(*) FROM {node} WHERE status = :status', array(':status' => 1))->fetchField();
  return array(
    'users' => (int) "'$users,
    '"'nodes' => (int) "'$nodes,
  );
}
EOF
php -l healthstats/healthstats.module'

